// ── Types ────────────────────────────────────────────────────────────────────

export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, unknown>[];
  headers: string[];
  errors: CSVError[];
  filter: (predicate: (row: Record<string, unknown>) => boolean) => Record<string, unknown>[];
  sum: (column: string) => number;
  average: (column: string) => number;
  count: () => number;
  groupBy: (column: string) => Map<unknown, Record<string, unknown>[]>;
}

// ── Field-level parsing ──────────────────────────────────────────────────────

function parseFields(line: string, delimiter: string, quote: string): string[] {
  const fields: string[] = [];
  let i = 0;
  const len = line.length;

  while (i <= len) {
    if (i === len) {
      // Trailing delimiter produced an empty trailing field
      // (only matters when the previous char was a delimiter).
      // We already pushed the last real field below, so break.
      break;
    }

    if (line[i] === quote) {
      // ── Quoted field ───────────────────────────────────────────────────
      i++; // skip opening quote
      let value = "";
      while (i < len) {
        if (line[i] === quote) {
          if (i + 1 < len && line[i + 1] === quote) {
            // Escaped quote
            value += quote;
            i += 2;
          } else {
            // Closing quote
            i++; // skip closing quote
            break;
          }
        } else {
          value += line[i];
          i++;
        }
      }
      fields.push(value);
      // Skip delimiter after closing quote (or we're at end)
      if (i < len && line[i] === delimiter) {
        i++;
      }
    } else {
      // ── Unquoted field ─────────────────────────────────────────────────
      let value = "";
      while (i < len && line[i] !== delimiter) {
        value += line[i];
        i++;
      }
      fields.push(value);
      if (i < len) {
        i++; // skip delimiter
        // If delimiter is the very last char, there's a trailing empty field
        if (i === len) {
          fields.push("");
        }
      }
    }
  }

  return fields;
}

// ── Line splitting that respects quoted fields ───────────────────────────────

function splitLines(
  input: string,
  lineSeparator: string,
  quote: string
): string[] {
  const lines: string[] = [];
  let current = "";
  let inQuotes = false;
  let i = 0;

  while (i < input.length) {
    if (input[i] === quote) {
      // Check for escaped quote (only inside quotes)
      if (inQuotes && i + 1 < input.length && input[i + 1] === quote) {
        current += quote + quote;
        i += 2;
        continue;
      }
      inQuotes = !inQuotes;
      current += input[i];
      i++;
    } else if (
      !inQuotes &&
      input.substring(i, i + lineSeparator.length) === lineSeparator
    ) {
      lines.push(current);
      current = "";
      i += lineSeparator.length;
    } else {
      current += input[i];
      i++;
    }
  }

  // Push whatever remains (could be the last line without a trailing separator)
  if (current.length > 0) {
    lines.push(current);
  }

  return lines;
}

// ── Type coercion ────────────────────────────────────────────────────────────

function coerce(value: string): unknown {
  // Null / empty
  if (value === "" || value === "null" || value === "NULL") {
    return null;
  }

  // Boolean (case-insensitive)
  const lower = value.toLowerCase();
  if (lower === "true") return true;
  if (lower === "false") return false;

  // Number – integers and floats.  Reject strings like "" (handled above),
  // strings with leading/trailing spaces that would parse, hex, etc.
  if (/^-?(\d+\.?\d*|\.\d+)$/.test(value)) {
    const num = Number(value);
    if (!Number.isNaN(num)) return num;
  }

  return value;
}

// ── Main entry point ─────────────────────────────────────────────────────────

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ",";
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator ?? "\n";

  const result: CSVResult = {
    rows: [],
    headers: [],
    errors: [],
    filter(predicate) {
      return this.rows.filter(predicate);
    },
    sum(column) {
      let total = 0;
      for (const row of this.rows) {
        const v = row[column];
        if (typeof v === "number") total += v;
      }
      return total;
    },
    average(column) {
      let total = 0;
      let count = 0;
      for (const row of this.rows) {
        const v = row[column];
        if (typeof v === "number") {
          total += v;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },
    count() {
      return this.rows.length;
    },
    groupBy(column) {
      const map = new Map<unknown, Record<string, unknown>[]>();
      for (const row of this.rows) {
        const key = row[column];
        let group = map.get(key);
        if (!group) {
          group = [];
          map.set(key, group);
        }
        group.push(row);
      }
      return map;
    },
  };

  // ── Trivial / empty input ──────────────────────────────────────────────
  const trimmed = input.trim();
  if (trimmed.length === 0) {
    return result;
  }

  // ── Split into lines (respecting quoted newlines) ──────────────────────
  const lines = splitLines(trimmed, lineSeparator, quote);

  if (lines.length === 0) {
    return result;
  }

  // ── Headers ────────────────────────────────────────────────────────────
  const headerFields = parseFields(lines[0], delimiter, quote);
  result.headers = headerFields;

  // ── Data rows ──────────────────────────────────────────────────────────
  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];

    // Skip completely blank lines
    if (line.trim() === "") continue;

    const fields = parseFields(line, delimiter, quote);

    if (fields.length !== headerFields.length) {
      result.errors.push({
        row: i + 1, // 1-based, header is row 1
        message: `Expected ${headerFields.length} fields but got ${fields.length}`,
      });
      continue; // skip malformed row
    }

    const row: Record<string, unknown> = {};
    for (let j = 0; j < headerFields.length; j++) {
      row[headerFields[j]] = coerce(fields[j]);
    }
    result.rows.push(row);
  }

  return result;
}

import { parseCSV } from "./csv-parser";

// ── Tiny test harness ────────────────────────────────────────────────────────

let passed = 0;
let failed = 0;
const failures: string[] = [];

function assert(condition: boolean, message: string): void {
  if (!condition) {
    failed++;
    failures.push(message);
    console.error(`  ✗ ${message}`);
  } else {
    passed++;
    console.log(`  ✓ ${message}`);
  }
}

function assertEqual(actual: unknown, expected: unknown, label: string): void {
  const a = JSON.stringify(actual);
  const e = JSON.stringify(expected);
  if (a !== e) {
    failed++;
    const msg = `${label}\n      expected: ${e}\n      actual:   ${a}`;
    failures.push(msg);
    console.error(`  ✗ ${msg}`);
  } else {
    passed++;
    console.log(`  ✓ ${label}`);
  }
}

function suite(name: string, fn: () => void): void {
  console.log(`\n▸ ${name}`);
  fn();
}

// ── Tests ────────────────────────────────────────────────────────────────────

suite("Basic parsing", () => {
  const csv = "name,age,city\nAlice,30,NYC\nBob,25,LA";
  const result = parseCSV(csv);

  assertEqual(result.headers, ["name", "age", "city"], "headers parsed");
  assertEqual(result.rows.length, 2, "two data rows");
  assertEqual(result.rows[0]["name"], "Alice", "first row name");
  assertEqual(result.rows[0]["age"], 30, "first row age is number");
  assertEqual(result.rows[1]["city"], "LA", "second row city");
  assertEqual(result.errors.length, 0, "no errors");
});

suite("Quoted fields with commas", () => {
  const csv = 'name,address\nAlice,"123 Main St, Apt 4"\nBob,"456 Oak Ave, Suite 10"';
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 2, "two data rows");
  assertEqual(result.rows[0]["address"], "123 Main St, Apt 4", "comma inside quotes preserved");
  assertEqual(result.rows[1]["address"], "456 Oak Ave, Suite 10", "second quoted field");
});

suite("Escaped quotes (double-double-quote)", () => {
  const csv = 'name,quote\nAlice,"She said ""hello"""\nBob,"A ""B"" C"';
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["quote"], 'She said "hello"', "escaped quotes become literal");
  assertEqual(result.rows[1]["quote"], 'A "B" C', "mid-field escaped quotes");
});

suite("Quoted fields containing newlines", () => {
  const csv = 'name,bio\nAlice,"Line 1\nLine 2"\nBob,simple';
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 2, "two data rows despite embedded newline");
  assertEqual(result.rows[0]["bio"], "Line 1\nLine 2", "newline preserved inside quotes");
  assertEqual(result.rows[1]["name"], "Bob", "row after embedded newline parsed correctly");
});

suite("Custom delimiters", () => {
  const csv = "name\tage\tactive\nAlice\t30\ttrue";
  const result = parseCSV(csv, { delimiter: "\t" });

  assertEqual(result.headers, ["name", "age", "active"], "tab-delimited headers");
  assertEqual(result.rows[0]["age"], 30, "tab-delimited value");
  assertEqual(result.rows[0]["active"], true, "boolean coerced");
});

suite("Custom quote character", () => {
  const csv = "name,address\nAlice,'123 Main, Apt 4'";
  const result = parseCSV(csv, { quote: "'" });

  assertEqual(result.rows[0]["address"], "123 Main, Apt 4", "single-quote wrapped field");
});

suite("Custom line separator", () => {
  const csv = "name,age\r\nAlice,30\r\nBob,25";
  const result = parseCSV(csv, { lineSeparator: "\r\n" });

  assertEqual(result.rows.length, 2, "CRLF line separator");
  assertEqual(result.rows[0]["name"], "Alice", "first row with CRLF");
  assertEqual(result.rows[1]["name"], "Bob", "second row with CRLF");
});

suite("Type coercion – integers", () => {
  const csv = "val\n0\n42\n-7\n1000000";
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["val"], 0, "zero");
  assertEqual(result.rows[1]["val"], 42, "positive int");
  assertEqual(result.rows[2]["val"], -7, "negative int");
  assertEqual(result.rows[3]["val"], 1000000, "large int");
});

suite("Type coercion – floats", () => {
  const csv = "val\n3.14\n-0.5\n.25\n100.0";
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["val"], 3.14, "pi-ish");
  assertEqual(result.rows[1]["val"], -0.5, "negative float");
  assertEqual(result.rows[2]["val"], 0.25, "leading-dot float");
  assertEqual(result.rows[3]["val"], 100.0, "trailing-zero float");
});

suite("Type coercion – booleans", () => {
  const csv = "val\ntrue\nfalse\nTRUE\nFALSE\nTrue\nFalse";
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["val"], true, "true");
  assertEqual(result.rows[1]["val"], false, "false");
  assertEqual(result.rows[2]["val"], true, "TRUE");
  assertEqual(result.rows[3]["val"], false, "FALSE");
  assertEqual(result.rows[4]["val"], true, "True");
  assertEqual(result.rows[5]["val"], false, "False");
});

suite("Type coercion – nulls", () => {
  const csv = "a,b,c\nnull,NULL,";
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["a"], null, "null string → null");
  assertEqual(result.rows[0]["b"], null, "NULL string → null");
  assertEqual(result.rows[0]["c"], null, "empty string → null");
});

suite("Type coercion – strings stay strings", () => {
  const csv = "val\nhello\n123abc\nabc123\n \n12.34.56";
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["val"], "hello", "plain string");
  assertEqual(result.rows[1]["val"], "123abc", "number-prefix string");
  assertEqual(result.rows[2]["val"], "abc123", "letter-prefix string");
  assertEqual(result.rows[3]["val"], " ", "whitespace stays string");
  assertEqual(result.rows[4]["val"], "12.34.56", "double-dot stays string");
});

suite("Malformed row error collection", () => {
  const csv = "a,b,c\n1,2,3\n4,5\n6,7,8\n9";
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 2, "only valid rows kept");
  assertEqual(result.errors.length, 2, "two errors collected");
  assertEqual(result.errors[0]["row"], 3, "first error on row 3");
  assert(result.errors[0]["message"].includes("2"), "error mentions actual field count");
  assertEqual(result.errors[1]["row"], 5, "second error on row 5");
});

suite("Malformed rows don't crash – parsing continues", () => {
  const csv = "x,y\n1,2\nbad\n3,4\nalso,bad,extra\n5,6";
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 3, "three valid rows");
  assertEqual(result.errors.length, 2, "two errors");
  assertEqual(result.rows[2]["x"], 5, "last valid row parsed");
});

suite("filter()", () => {
  const csv = "name,age\nAlice,30\nBob,25\nCharlie,35";
  const result = parseCSV(csv);

  const over28 = result.filter((r) => (r["age"] as number) > 28);
  assertEqual(over28.length, 2, "filter returns matching rows");
  assertEqual(over28[0]["name"], "Alice", "first match");
  assertEqual(over28[1]["name"], "Charlie", "second match");

  const none = result.filter(() => false);
  assertEqual(none.length, 0, "filter returns empty when nothing matches");
});

suite("sum()", () => {
  const csv = "item,price\napple,1.5\nbanana,2.0\ncherry,3.5";
  const result = parseCSV(csv);

  assertEqual(result.sum("price"), 7, "sum of prices");
  assertEqual(result.sum("item"), 0, "sum of non-numeric column is 0");
  assertEqual(result.sum("nonexistent"), 0, "sum of missing column is 0");
});

suite("average()", () => {
  const csv = "item,price\napple,10\nbanana,20\ncherry,30";
  const result = parseCSV(csv);

  assertEqual(result.average("price"), 20, "average of prices");
  assertEqual(result.average("item"), 0, "average of non-numeric column is 0");
  assertEqual(result.average("nonexistent"), 0, "average of missing column is 0");
});

suite("average() with mixed types", () => {
  const csv = "name,score\nAlice,100\nBob,N/A\nCharlie,200";
  const result = parseCSV(csv);

  // Only numeric values count: (100+200)/2 = 150
  assertEqual(result.average("score"), 150, "average skips non-numeric");
});

suite("count()", () => {
  const csv = "x\n1\n2\n3";
  const result = parseCSV(csv);
  assertEqual(result.count(), 3, "count returns row count");
});

suite("groupBy()", () => {
  const csv = "dept,name,salary\neng,Alice,100\nhr,Bob,90\neng,Charlie,120\nhr,Dave,80";
  const result = parseCSV(csv);
  const groups = result.groupBy("dept");

  assertEqual(groups.size, 2, "two groups");
  assertEqual(groups.get("eng")!.length, 2, "eng has 2 members");
  assertEqual(groups.get("hr")!.length, 2, "hr has 2 members");
  assertEqual(groups.get("eng")![0]["name"], "Alice", "eng first member");
  assertEqual(groups.get("eng")![1]["name"], "Charlie", "eng second member");
});

suite("groupBy() with coerced keys", () => {
  const csv = "active,name\ntrue,Alice\nfalse,Bob\ntrue,Charlie";
  const result = parseCSV(csv);
  const groups = result.groupBy("active");

  assertEqual(groups.get(true)!.length, 2, "true group has 2");
  assertEqual(groups.get(false)!.length, 1, "false group has 1");
});

suite("Edge case – empty input", () => {
  const result = parseCSV("");
  assertEqual(result.headers.length, 0, "no headers");
  assertEqual(result.rows.length, 0, "no rows");
  assertEqual(result.errors.length, 0, "no errors");
  assertEqual(result.count(), 0, "count is 0");
});

suite("Edge case – whitespace-only input", () => {
  const result = parseCSV("   \n  \n ");
  assertEqual(result.rows.length, 0, "no rows from whitespace");
});

suite("Edge case – headers only, no data", () => {
  const result = parseCSV("a,b,c");
  assertEqual(result.headers, ["a", "b", "c"], "headers parsed");
  assertEqual(result.rows.length, 0, "no data rows");
  assertEqual(result.count(), 0, "count is 0");
  assertEqual(result.sum("a"), 0, "sum on empty is 0");
  assertEqual(result.average("a"), 0, "average on empty is 0");
});

suite("Edge case – single column", () => {
  const csv = "value\n42\nhello\ntrue";
  const result = parseCSV(csv);

  assertEqual(result.headers, ["value"], "single header");
  assertEqual(result.rows.length, 3, "three rows");
  assertEqual(result.rows[0]["value"], 42, "number coerced");
  assertEqual(result.rows[1]["value"], "hello", "string kept");
  assertEqual(result.rows[2]["value"], true, "boolean coerced");
});

suite("Edge case – single row", () => {
  const csv = "a,b,c\n1,2,3";
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 1, "one row");
  assertEqual(result.rows[0]["a"], 1, "value a");
  assertEqual(result.rows[0]["b"], 2, "value b");
  assertEqual(result.rows[0]["c"], 3, "value c");
});

suite("Edge case – very large fields", () => {
  const bigValue = "x".repeat(100_000);
  const csv = `col\n${bigValue}`;
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 1, "one row with large field");
  assertEqual((result.rows[0]["col"] as string).length, 100_000, "field length preserved");
});

suite("Edge case – very large quoted field with commas and quotes", () => {
  // Build a big field with embedded commas and escaped quotes
  const chunk = 'hello, world ""and"" stuff. ';
  const bigInner = chunk.repeat(1000);
  const escaped = bigInner.replace(/"/g, '""');
  const csv = `data\n"${escaped}"`;
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 1, "one row");
  assertEqual(result.rows[0]["data"], bigInner, "large quoted field preserved");
});

suite("Trailing delimiter produces empty field", () => {
  const csv = "a,b\n1,\n,2";
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["a"], 1, "first field");
  assertEqual(result.rows[0]["b"], null, "trailing empty → null");
  assertEqual(result.rows[1]["a"], null, "leading empty → null");
  assertEqual(result.rows[1]["b"], 2, "second field");
});

suite("All options combined", () => {
  const csv = "name|age|active\r\n'Alice, ""A""'|30|true\r\n'Bob'|25|false";
  const result = parseCSV(csv, {
    delimiter: "|",
    quote: "'",
    lineSeparator: "\r\n",
  });

  assertEqual(result.headers, ["name", "age", "active"], "headers with custom opts");
  assertEqual(result.rows[0]["name"], 'Alice, "A"', "quoted with custom quote char + escaped");
  assertEqual(result.rows[0]["age"], 30, "number coerced");
  assertEqual(result.rows[0]["active"], true, "boolean coerced");
  assertEqual(result.rows[1]["name"], "Bob", "second row name");
});

suite("Quoted field that is just escaped quotes", () => {
  const csv = 'val\n""""';
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["val"], '"', "four quotes → one literal quote");
});

suite("Multiple errors on different rows", () => {
  const csv = "a,b\n1,2\nx\n3,4\ny\nz\n5,6";
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 3, "three valid rows");
  assertEqual(result.errors.length, 3, "three errors");
  const errorRows = result.errors.map((e) => e.row);
  assertEqual(errorRows, [3, 5, 6], "errors on correct rows");
});

suite("filter + aggregation chaining", () => {
  const csv = "dept,salary\neng,100\nhr,80\neng,120\nhr,90\neng,110";
  const result = parseCSV(csv);

  // Use filter then manually aggregate
  const engRows = result.filter((r) => r["dept"] === "eng");
  assertEqual(engRows.length, 3, "3 eng rows");

  // Sum eng salaries manually
  const engSum = engRows.reduce((s, r) => s + (r["salary"] as number), 0);
  assertEqual(engSum, 330, "eng salary sum");
});

// ── Summary ──────────────────────────────────────────────────────────────────

console.log("\n" + "═".repeat(50));
console.log(`  ${passed} passed, ${failed} failed`);
if (failures.length > 0) {
  console.log("\nFailures:");
  failures.forEach((f) => console.log(`  - ${f}`));
  process.exit(1);
} else {
  console.log("  All tests passed! 🎉");
}

