  assertEqual(result.count(), 3, "count returns row count");
});

suite("groupBy()", () => {
  const csv = "dept,name,salary\neng,Alice,100\nhr,Bob,90\neng,Charlie,120\nhr,Dave,80";
  const result = parseCSV(csv);
  const groups = result.groupBy("dept");

  assertEqual(groups.size, 2, "two groups");
  assertEqual(groups.get("eng")!.length, 2, "eng has 2 members");
  assertEqual(groups.get("hr")!.length, 2, "hr has 2 members");
  assertEqual(groups.get("eng")![0]["name"], "Alice", "eng first member");
  assertEqual(groups.get("eng")![1]["name"], "Charlie", "eng second member");
});

suite("groupBy() with coerced keys", () => {
  const csv = "active,name\ntrue,Alice\nfalse,Bob\ntrue,Charlie";
  const result = parseCSV(csv);
  const groups = result.groupBy("active");

  assertEqual(groups.get(true)!.length, 2, "true group has 2");
  assertEqual(groups.get(false)!.length, 1, "false group has 1");
});

suite("Edge case – empty input", () => {
  const result = parseCSV("");
  assertEqual(result.headers.length, 0, "no headers");
  assertEqual(result.rows.length, 0, "no rows");
  assertEqual(result.errors.length, 0, "no errors");
  assertEqual(result.count(), 0, "count is 0");
});

suite("Edge case – whitespace-only input", () => {
  const result = parseCSV("   \n  \n ");
  assertEqual(result.rows.length, 0, "no rows from whitespace");
});

suite("Edge case – headers only, no data", () => {
  const result = parseCSV("a,b,c");
  assertEqual(result.headers, ["a", "b", "c"], "headers parsed");
  assertEqual(result.rows.length, 0, "no data rows");
  assertEqual(result.count(), 0, "count is 0");
  assertEqual(result.sum("a"), 0, "sum on empty is 0");
  assertEqual(result.average("a"), 0, "average on empty is 0");
});

suite("Edge case – single column", () => {
  const csv = "value\n42\nhello\ntrue";
  const result = parseCSV(csv);

  assertEqual(result.headers, ["value"], "single header");
  assertEqual(result.rows.length, 3, "three rows");
  assertEqual(result.rows[0]["value"], 42, "number coerced");
  assertEqual(result.rows[1]["value"], "hello", "string kept");
  assertEqual(result.rows[2]["value"], true, "boolean coerced");
});

suite("Edge case – single row", () => {
  const csv = "a,b,c\n1,2,3";
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 1, "one row");
  assertEqual(result.rows[0]["a"], 1, "value a");
  assertEqual(result.rows[0]["b"], 2, "value b");
  assertEqual(result.rows[0]["c"], 3, "value c");
});

suite("Edge case – very large fields", () => {
  const bigValue = "x".repeat(100_000);
  const csv = `col\n${bigValue}`;
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 1, "one row with large field");
  assertEqual((result.rows[0]["col"] as string).length, 100_000, "field length preserved");
});

suite("Edge case – very large quoted field with commas and quotes", () => {
  // Build a big field with embedded commas and escaped quotes
  const chunk = 'hello, world ""and"" stuff. ';
  const bigInner = chunk.repeat(1000);
  const escaped = bigInner.replace(/"/g, '""');
  const csv = `data\n"${escaped}"`;
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 1, "one row");
  assertEqual(result.rows[0]["data"], bigInner, "large quoted field preserved");
});

suite("Trailing delimiter produces empty field", () => {
  const csv = "a,b\n1,\n,2";
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["a"], 1, "first field");
  assertEqual(result.rows[0]["b"], null, "trailing empty → null");
  assertEqual(result.rows[1]["a"], null, "leading empty → null");
  assertEqual(result.rows[1]["b"], 2, "second field");
});

suite("All options combined", () => {
  const csv = "name|age|active\r\n'Alice, ""A""'|30|true\r\n'Bob'|25|false";
  const result = parseCSV(csv, {
    delimiter: "|",
    quote: "'",
    lineSeparator: "\r\n",
  });

  assertEqual(result.headers, ["name", "age", "active"], "headers with custom opts");
  assertEqual(result.rows[0]["name"], 'Alice, "A"', "quoted with custom quote char + escaped");
  assertEqual(result.rows[0]["age"], 30, "number coerced");
  assertEqual(result.rows[0]["active"], true, "boolean coerced");
  assertEqual(result.rows[1]["name"], "Bob", "second row name");
});

suite("Quoted field that is just escaped quotes", () => {
  const csv = 'val\n""""';
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["val"], '"', "four quotes → one literal quote");
});

suite("Multiple errors on different rows", () => {
  const csv = "a,b\n1,2\nx\n3,4\ny\nz\n5,6";
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 3, "three valid rows");
  assertEqual(result.errors.length, 3, "three errors");
  const errorRows = result.errors.map((e) => e.row);
  assertEqual(errorRows, [3, 5, 6], "errors on correct rows");
});

suite("filter + aggregation chaining", () => {
  const csv = "dept,salary\neng,100\nhr,80\neng,120\nhr,90\neng,110";
  const result = parseCSV(csv);

  // Use filter then manually aggregate
