function parseFields(line, delimiter, quote) {
  const fields = [];
  let i = 0;
  const len = line.length;

  while (i <= len) {
    if (i === len) break;

    if (line[i] === quote) {
      i++;
      let value = "";
      while (i < len) {
        if (line[i] === quote) {
          if (i + 1 < len && line[i + 1] === quote) {
            value += quote;
            i += 2;
          } else {
            i++;
            break;
          }
        } else {
          value += line[i];
          i++;
        }
      }
      fields.push(value);
      if (i < len && line[i] === delimiter) i++;
    } else {
      let value = "";
      while (i < len && line[i] !== delimiter) {
        value += line[i];
        i++;
      }
      fields.push(value);
      if (i < len) {
        i++;
        if (i === len) fields.push("");
      }
    }
  }
  return fields;
}

function splitLines(input, lineSeparator, quote) {
  const lines = [];
  let current = "";
  let inQuotes = false;
  let i = 0;

  while (i < input.length) {
    if (input[i] === quote) {
      if (inQuotes && i + 1 < input.length && input[i + 1] === quote) {
        current += quote + quote;
        i += 2;
        continue;
      }
      inQuotes = !inQuotes;
      current += input[i];
      i++;
    } else if (!inQuotes && input.substring(i, i + lineSeparator.length) === lineSeparator) {
      lines.push(current);
      current = "";
      i += lineSeparator.length;
    } else {
      current += input[i];
      i++;
    }
  }
  if (current.length > 0) lines.push(current);
  return lines;
}

function coerce(value) {
  if (value === "" || value === "null" || value === "NULL") return null;
  const lower = value.toLowerCase();
  if (lower === "true") return true;
  if (lower === "false") return false;
  if (/^-?(\d+\.?\d*|\.\d+)$/.test(value)) {
    const num = Number(value);
    if (!Number.isNaN(num)) return num;
  }
  return value;
}

function parseCSV(input, options) {
  const delimiter = (options && options.delimiter) || ",";
  const quote = (options && options.quote) || '"';
  const lineSeparator = (options && options.lineSeparator) || "\n";

  const result = {
    rows: [],
    headers: [],
    errors: [],
    filter(predicate) { return this.rows.filter(predicate); },
    sum(column) {
      let total = 0;
      for (const row of this.rows) {
        const v = row[column];
        if (typeof v === "number") total += v;
      }
      return total;
    },
    average(column) {
      let total = 0, count = 0;
      for (const row of this.rows) {
        const v = row[column];
        if (typeof v === "number") { total += v; count++; }
      }
      return count === 0 ? 0 : total / count;
    },
    count() { return this.rows.length; },
    groupBy(column) {
      const map = new Map();
      for (const row of this.rows) {
        const key = row[column];
        let group = map.get(key);
        if (!group) { group = []; map.set(key, group); }
        group.push(row);
      }
      return map;
    },
  };

  const trimmed = input.trim();
  if (trimmed.length === 0) return result;

  const lines = splitLines(trimmed, lineSeparator, quote);
  if (lines.length === 0) return result;

  const headerFields = parseFields(lines[0], delimiter, quote);
  result.headers = headerFields;

  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];
    if (line.trim() === "") continue;
    const fields = parseFields(line, delimiter, quote);
    if (fields.length !== headerFields.length) {
      result.errors.push({ row: i + 1, message: `Expected ${headerFields.length} fields but got ${fields.length}` });
      continue;
    }
    const row = {};
    for (let j = 0; j < headerFields.length; j++) {
      row[headerFields[j]] = coerce(fields[j]);
    }
    result.rows.push(row);
  }
  return result;
}

