// ── Types ────────────────────────────────────────────────────────────────────

export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, unknown>[];
  headers: string[];
  errors: CSVError[];
  filter: (predicate: (row: Record<string, unknown>) => boolean) => Record<string, unknown>[];
  sum: (column: string) => number;
  average: (column: string) => number;
  count: () => number;
  groupBy: (column: string) => Map<unknown, Record<string, unknown>[]>;
}

// ── Field-level parsing ──────────────────────────────────────────────────────

function parseFields(line: string, delimiter: string, quote: string): string[] {
  const fields: string[] = [];
  let i = 0;
  const len = line.length;

  while (i <= len) {
    if (i === len) {
      // Trailing delimiter produced an empty trailing field
      // (only matters when the previous char was a delimiter).
      // We already pushed the last real field below, so break.
      break;
    }

    if (line[i] === quote) {
      // ── Quoted field ───────────────────────────────────────────────────
      i++; // skip opening quote
      let value = "";
      while (i < len) {
        if (line[i] === quote) {
          if (i + 1 < len && line[i + 1] === quote) {
            // Escaped quote
            value += quote;
            i += 2;
          } else {
            // Closing quote
            i++; // skip closing quote
            break;
          }
        } else {
          value += line[i];
          i++;
        }
      }
      fields.push(value);
      // Skip delimiter after closing quote (or we're at end)
      if (i < len && line[i] === delimiter) {
        i++;
      }
    } else {
      // ── Unquoted field ─────────────────────────────────────────────────
      let value = "";
      while (i < len && line[i] !== delimiter) {
        value += line[i];
        i++;
      }
      fields.push(value);
      if (i < len) {
        i++; // skip delimiter
        // If delimiter is the very last char, there's a trailing empty field
        if (i === len) {
          fields.push("");
        }
      }
    }
  }

  return fields;
}

// ── Line splitting that respects quoted fields ───────────────────────────────

function splitLines(
  input: string,
  lineSeparator: string,
  quote: string
): string[] {
  const lines: string[] = [];
  let current = "";
  let inQuotes = false;
  let i = 0;

  while (i < input.length) {
    if (input[i] === quote) {
      // Check for escaped quote (only inside quotes)
      if (inQuotes && i + 1 < input.length && input[i + 1] === quote) {
        current += quote + quote;
        i += 2;
        continue;
      }
      inQuotes = !inQuotes;
      current += input[i];
      i++;
    } else if (
      !inQuotes &&
      input.substring(i, i + lineSeparator.length) === lineSeparator
    ) {
      lines.push(current);
      current = "";
      i += lineSeparator.length;
    } else {
      current += input[i];
      i++;
    }
  }

  // Push whatever remains (could be the last line without a trailing separator)
  if (current.length > 0) {
    lines.push(current);
  }

  return lines;
}

// ── Type coercion ────────────────────────────────────────────────────────────

function coerce(value: string): unknown {
  // Null / empty
  if (value === "" || value === "null" || value === "NULL") {
    return null;
  }

  // Boolean (case-insensitive)
  const lower = value.toLowerCase();
  if (lower === "true") return true;
  if (lower === "false") return false;

  // Number – integers and floats.  Reject strings like "" (handled above),
  // strings with leading/trailing spaces that would parse, hex, etc.
  if (/^-?(\d+\.?\d*|\.\d+)$/.test(value)) {
    const num = Number(value);
    if (!Number.isNaN(num)) return num;
  }

  return value;
}

// ── Main entry point ─────────────────────────────────────────────────────────

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ",";
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator ?? "\n";

  const result: CSVResult = {
    rows: [],
    headers: [],
    errors: [],
    filter(predicate) {
      return this.rows.filter(predicate);
    },
    sum(column) {
      let total = 0;
      for (const row of this.rows) {
        const v = row[column];
        if (typeof v === "number") total += v;
      }
      return total;
    },
    average(column) {
      let total = 0;
      let count = 0;
      for (const row of this.rows) {
        const v = row[column];
        if (typeof v === "number") {
          total += v;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },
    count() {
      return this.rows.length;
    },
    groupBy(column) {
      const map = new Map<unknown, Record<string, unknown>[]>();
      for (const row of this.rows) {
        const key = row[column];
        let group = map.get(key);
        if (!group) {
          group = [];
          map.set(key, group);
        }
        group.push(row);
      }
      return map;
    },
  };

  // ── Trivial / empty input ──────────────────────────────────────────────
  const trimmed = input.trim();
  if (trimmed.length === 0) {
    return result;
  }

  // ── Split into lines (respecting quoted newlines) ──────────────────────
  const lines = splitLines(trimmed, lineSeparator, quote);

  if (lines.length === 0) {
    return result;
  }

  // ── Headers ────────────────────────────────────────────────────────────
  const headerFields = parseFields(lines[0], delimiter, quote);
  result.headers = headerFields;

  // ── Data rows ──────────────────────────────────────────────────────────
  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];

    // Skip completely blank lines
    if (line.trim() === "") continue;

    const fields = parseFields(line, delimiter, quote);

    if (fields.length !== headerFields.length) {
      result.errors.push({
        row: i + 1, // 1-based, header is row 1
        message: `Expected ${headerFields.length} fields but got ${fields.length}`,
      });
      continue; // skip malformed row
    }

    const row: Record<string, unknown> = {};
    for (let j = 0; j < headerFields.length; j++) {
      row[headerFields[j]] = coerce(fields[j]);
    }
    result.rows.push(row);
  }

  return result;
}
